const body = $input.first().json;
const results = body.results || [];

if (results.length === 0) {
  return [{ json: { _no_docs: true } }];
}

return results.map(page => {
  const props = page.properties;
  const title = props.Titel?.title?.[0]?.plain_text || 'Kein Titel';
  const typ = props.Typ?.select?.name || 'Protokoll';
  const dokumenttyp = props.Dokumenttyp?.select?.name || 'Board';
  const meetingDatum = props['Meeting Datum']?.date?.start || null;
  const oneDriveUrl = props['OneDrive URL']?.url || '';
  const filename = props['Quelle Board']?.rich_text?.[0]?.plain_text || '';
  const quelleBoard = props['Quelle Board']?.rich_text?.[0]?.plain_text || '';
  const gruppenIds = (props.DB_Gruppen?.relation || []).map(r => r.id);
  const kundenIds = (props['DB Kunden']?.relation || []).map(r => r.id);

  return {
    json: {
      notion_page_id: page.id,
      title,
      typ,
      dokumenttyp,
      meeting_datum: meetingDatum,
      onedrive_url: oneDriveUrl,
      quelle_board: quelleBoard,
      gruppen_ids: gruppenIds,
      kunden_ids: kundenIds
    }
  };
});

const doc = $input.item.json;
const dokumenttyp = doc.dokumenttyp;

let primaryId, isGruppe;
if (dokumenttyp === 'Individuell') {
  // Individuell: primary source is always a Kunden
  primaryId = doc.kunden_ids?.[0] || null;
  isGruppe = false;
} else {
  // Board or Beides: primary source is Gruppe
  primaryId = doc.gruppen_ids?.[0] || doc.kunden_ids?.[0] || null;
  isGruppe = doc.gruppen_ids?.length > 0;
}

return {
  json: {
    ...doc,
    primary_source_id: primaryId,
    primary_is_gruppe: isGruppe
  }
};

const sourcePage = $input.item.json;
const doc = $('Loop: Dokumente').item.json;
const primary = $('Code: Primäre Quelle bestimmen').item.json;

const props = sourcePage.properties;
// Use primary_is_gruppe from Code: Primäre Quelle bestimmen (already computed upstream)
// This correctly handles Beides with empty gruppen_ids (falls back to Kunden as primary)
const isGruppe = primary.primary_is_gruppe === true;

// Try multiple possible property name variants (Notion is case-sensitive)
const getText = (p) => p?.rich_text?.[0]?.plain_text || p?.text?.[0]?.plain_text || '';

const spaceKey = getText(props['Confluence Space Key']) || getText(props['ConfluenceSpaceKey']) || getText(props['Confluence_Space_Key']) || '';
const parentPageId = getText(props['Confluence PageID']) || getText(props['ConfluencePageID']) || '';

const sourceName = props.Name?.title?.[0]?.plain_text || '';
const subfolderName = doc.typ === 'Agenda' ? 'Agenda PAB' : 'Protokolle PAB';

// Expose raw props for debugging if config is missing
const missingFields = [];
if (!spaceKey) missingFields.push('Confluence Space Key');
if (!parentPageId) missingFields.push('Confluence PageID');

return {
  json: {
    ...doc,
    confluence_space_key: spaceKey,
    confluence_parent_page_id: parentPageId,
    confluence_subfolder: subfolderName,
    source_name: sourceName,
    _config_missing: missingFields.length > 0,
    _config_missing_fields: missingFields
  }
};

const results = $input.item.json.results || [];
const doc = $('Code: Confluence-Ziel aufbauen').item.json;

return {
  json: {
    ...doc,
    confluence_subfolder_id: results[0]?.id || ''
  }
};

