const createdPage = $input.item.json;
const doc = $('Code: Confluence-Ziel aufbauen').item.json;

return {
  json: {
    ...doc,
    confluence_subfolder_id: createdPage.id
  }
};

const shareUrl = $input.item.json.onedrive_url || '';
const encoded = 'u!' + Buffer.from(shareUrl).toString('base64').replace(/=+$/, '').replace(/\//g, '_').replace(/\+/g, '-');
return {
  json: {
    ...$input.item.json,
    graph_download_url: `https://graph.microsoft.com/v1.0/shares/${encoded}/driveItem/content`
  }
};

const doc = $('Loop: Dokumente').item.json;
const subfolder = $('Code: Subfolder zusammenführen').item.json;

const pageId = subfolder.confluence_subfolder_id || '';
const kunden_ids = doc.kunden_ids || [];
const notionProps = {};

// For 'Beides' WITH Kunden: defer ConfluenceSync=true until after Kunden loop completes.
// All other cases (Board, Individuell, Beides without Kunden): set it now.
const isBeidesMitKunden = doc.dokumenttyp === 'Beides' && kunden_ids.length > 0;
if (!isBeidesMitKunden) {
  notionProps['ConfluenceSync'] = { checkbox: true };
}
if (pageId) {
  notionProps['Confluence PageID'] = { rich_text: [{ text: { content: pageId } }] };
}

return {
  json: {
    notion_page_id: doc.notion_page_id,
    confluence_page_id: pageId,
    dokumenttyp: doc.dokumenttyp,
    kunden_ids: kunden_ids,
    body: JSON.stringify({ properties: notionProps })
  }
};

const notionUpdate = $('Code: Notion-Update vorbereiten').first().json;
const docData = $('Loop: Dokumente').first().json;
const primaryData = $('Code: Primäre Quelle bestimmen').first().json;
const kundenIds = notionUpdate.kunden_ids || [];
const dokumenttyp = notionUpdate.dokumenttyp;
const primaryIsGruppe = primaryData.primary_is_gruppe === true;

if (kundenIds.length === 0) {
  return [{ json: { _no_kunden: true } }];
}

// Skip the first Kunden if the main flow already handled it:
// - Always for 'Individuell' (primary = first Kunden)
// - For 'Beides' only when gruppen_ids was empty (primary_is_gruppe=false → fell back to first Kunden)
const mainFlowUsedFirstKunde = dokumenttyp === 'Individuell' || (dokumenttyp === 'Beides' && !primaryIsGruppe);
const idsToProcess = mainFlowUsedFirstKunde ? kundenIds.slice(1) : kundenIds;

if (idsToProcess.length === 0) {
  return [{ json: { _no_kunden: true } }];
}

return idsToProcess.map(id => ({
  json: {
    kunden_id: id,
    primary_page_data: {
      notion_page_id: notionUpdate.notion_page_id,
      confluence_page_id: notionUpdate.confluence_page_id,
      onedrive_url: docData.onedrive_url || '',
      typ: docData.typ || 'Protokoll',
      title: docData.title || '',
      meeting_datum: docData.meeting_datum || null
    }
  }
}));

const kundenPage = $input.item.json;
const loopData = $('Loop: Kunden-Spaces').item.json;
const primary = loopData.primary_page_data;

const props = kundenPage.properties;
const getText = (p) => p?.rich_text?.[0]?.plain_text || p?.text?.[0]?.plain_text || '';

const spaceKey = getText(props['ConfluenceSpaceKey']) || getText(props['Confluence Space Key']) || '';
const parentId = getText(props['Confluence PageID']) || '';
const sourceName = props.Name?.title?.[0]?.plain_text || '';
const subfolderName = primary.typ === 'Agenda' ? 'Agenda PAB' : 'Protokolle PAB';

const missingFields = [];
if (!spaceKey) missingFields.push('ConfluenceSpaceKey');
if (!parentId) missingFields.push('Confluence PageID');

return {
  json: {
    kunden_space_key: spaceKey,
    kunden_parent_id: parentId,
    kunden_subfolder_name: subfolderName,
    source_name: sourceName,
    notion_page_id: primary.notion_page_id || '',
    existing_confluence_page_id: primary.confluence_page_id || '',
    onedrive_url: primary.onedrive_url || '',
    typ: primary.typ || 'Protokoll',
    title: primary.title || '',
    meeting_datum: primary.meeting_datum || null,
    _config_missing: missingFields.length > 0,
    _config_missing_fields: missingFields
  }
};

const subfolder = $('Code: Kunden-Subfolder zusammenführen').item.json;
const subfolderId = subfolder.kunden_subfolder_id || '';
const notionPageId = subfolder.notion_page_id || '';
const existingId = subfolder.existing_confluence_page_id || '';
const allIds = [existingId, subfolderId].filter(Boolean).join(',');

return {
  json: {
    notion_page_id: notionPageId,
    all_page_ids: allIds
  }
};

const d = $input.item.json;
const info = {
  confluence_space_key: d.confluence_space_key || 'LEER',
  confluence_parent_page_id: d.confluence_parent_page_id || 'LEER',
  confluence_subfolder: d.confluence_subfolder || 'LEER',
  onedrive_url: (d.onedrive_url || 'LEER').substring(0, 100),
  config_missing: d._config_missing,
  missing_fields: d._config_missing_fields
};
console.log('[DEBUG 1 - Confluence Ziel]', JSON.stringify(info));
return { json: { ...d, _debug_ziel: info } };

const d = $input.item.json;
const info = {
  response_size: d.size,
  results_count: (d.results || []).length,
  first_result_id: d.results?.[0]?.id || 'KEINE',
  first_result_title: d.results?.[0]?.title || 'KEINE',
  raw_keys: Object.keys(d).join(', ')
};
console.log('[DEBUG 2 - Suche Ergebnis]', JSON.stringify(info));
return { json: { ...d, _debug_suche: info } };

const d = $input.item.json;
const info = {
  confluence_subfolder_id: d.confluence_subfolder_id || 'LEER',
  confluence_subfolder: d.confluence_subfolder || 'LEER',
  onedrive_url: (d.onedrive_url || 'LEER').substring(0, 100)
};
console.log('[DEBUG 3 - Subfolder ID]', JSON.stringify(info));
return { json: { ...d, _debug_subfolder: info } };

const d = $input.item.json;
const info = {
  graph_download_url: d.graph_download_url || 'LEER',
  onedrive_url_raw: (d.onedrive_url || 'LEER').substring(0, 100)
};
console.log('[DEBUG 4 - Graph URL]', JSON.stringify(info));
return { json: { ...d, _debug_graph: info } };

const d = $input.item.json;
const info = {
  status_code: d.statusCode || d.status || 'unbekannt',
  result_id: d.id || d.results?.[0]?.id || 'KEINE',
  result_title: d.title || d.results?.[0]?.title || 'KEINE',
  error_message: d.message || d.errorMessage || d.data?.message || null,
  raw_keys: Object.keys(d).join(', ')
};
console.log('[DEBUG 5 - Upload Status]', JSON.stringify(info));
return { json: { ...d, _debug_upload: info } };

const results = $input.item.json.results || [];
const prev = $('Code: Kunden-Confluence-Ziel').item.json;
return {
  json: {
    ...prev,
    kunden_subfolder_id: results[0]?.id || ''
  }
};

const createdPage = $input.item.json;
const prev = $('Code: Kunden-Confluence-Ziel').item.json;
return {
  json: {
    ...prev,
    kunden_subfolder_id: createdPage.id || ''
  }
};

const d = $input.item.json;
const shareUrl = d.onedrive_url || '';
const encoded = 'u!' + Buffer.from(shareUrl).toString('base64').replace(/=+$/, '').replace(/\//g, '_').replace(/\+/g, '-');
return {
  json: {
    ...d,
    kunden_graph_url: `https://graph.microsoft.com/v1.0/shares/${encoded}/driveItem/content`
  }
};

const d = $input.item.json;
const info = {
  kunden_space_key: d.kunden_space_key || 'LEER',
  kunden_parent_id: d.kunden_parent_id || 'LEER',
  kunden_subfolder_name: d.kunden_subfolder_name || 'LEER',
  onedrive_url: (d.onedrive_url || 'LEER').substring(0, 100),
  config_missing: d._config_missing,
  missing_fields: d._config_missing_fields
};
console.log('[DEBUG K1 - Kunden Ziel]', JSON.stringify(info));
return { json: { ...d, _debug_kunden_ziel: info } };

const d = $input.item.json;
const info = {
  response_size: d.size,
  results_count: (d.results || []).length,
  first_result_id: d.results?.[0]?.id || 'KEINE',
  first_result_title: d.results?.[0]?.title || 'KEINE'
};
console.log('[DEBUG K2 - Kunden Suche]', JSON.stringify(info));
return { json: { ...d, _debug_kunden_suche: info } };

const d = $input.item.json;
const info = {
  status_code: d.statusCode || d.status || 'unbekannt',
  result_id: d.id || d.results?.[0]?.id || 'KEINE',
  error_message: d.message || d.errorMessage || d.data?.message || null,
  raw_keys: Object.keys(d).join(', ')
};
console.log('[DEBUG K3 - Kunden Upload]', JSON.stringify(info));
return { json: { ...d, _debug_kunden_upload: info } };

const items = $input.all();
const first = items[0]?.json || {};

// n8n splitInBatches DONE may send different item shapes depending on version:
// A) Original loop-input items: { kunden_id, primary_page_data: { notion_page_id } }
// B) Feedback items = Notion PATCH response: { id: UUID, object: 'page', ... }
const notionPageId =
  first.primary_page_data?.notion_page_id ||
  (first.object === 'page' ? first.id : null) ||
  '';

console.log('[BEIDES-SYNC] items:', items.length, 'notionPageId:', notionPageId, 'first.object:', first.object, 'keys:', Object.keys(first).slice(0, 6).join(','));

return [{
  json: {
    notion_page_id: notionPageId || null,
    _skip: !notionPageId,
    body: notionPageId
      ? JSON.stringify({ properties: { 'ConfluenceSync': { checkbox: true } } })
      : '{}'
  }
}];

// Wenn Upload fehlschlug (continueOnFail), enthält der Input einen 'error'-Key
var inputJson = $input.item.json;
if (inputJson.error) {
  console.log('[LABEL] Upload fehlgeschlagen – Label wird übersprungen:', JSON.stringify(inputJson.error).substring(0, 100));
  return { json: { _skip_label: true } };
}

// Attachment-ID aus erfolgreichem Upload-Response holen
var attachmentId = '';
try {
  attachmentId = (inputJson.results && inputJson.results[0] && inputJson.results[0].id)
    || inputJson.id || '';
} catch(e) {}

var typ = '';
try { typ = $('Loop: Dokumente').item.json.typ || 'Protokoll'; } catch(e) { typ = 'Protokoll'; }
var labelName = typ.toLowerCase() === 'agenda' ? 'agenda' : 'protokoll';

console.log('[LABEL] attachmentId:', attachmentId, '| labelName:', labelName);
if (!attachmentId) {
  console.log('[LABEL] Keine Attachment-ID – übersprungen. Keys:', Object.keys(inputJson).join(', '));
  return { json: { _skip_label: true } };
}

return { json: {
  label_page_id: attachmentId,
  label_name: labelName,
  label_url: 'https://blboardsolutions.atlassian.net/wiki/rest/api/content/' + attachmentId + '/label'
} };

// Attachment-ID aus Kunden-Upload-Response holen
var attachmentId = '';
try {
  var res = $input.item.json;
  attachmentId = (res.results && res.results[0] && res.results[0].id)
    || res.id || '';
} catch(e) {}

// Fallback: Kunden-Unterordner-ID (falls Upload fehlschlug oder Anhang existierte)
if (!attachmentId) {
  try { attachmentId = $('Code: Kunden-Subfolder zusammenführen').item.json.kunden_subfolder_id || ''; } catch(e) {}
}

var typ = '';
try { typ = $('Loop: Dokumente').item.json.typ || 'Protokoll'; } catch(e) { typ = 'Protokoll'; }
var labelName = typ.toLowerCase() === 'agenda' ? 'agenda' : 'protokoll';

console.log('[LABEL Kunden] id:', attachmentId, '| label:', labelName);

// Kein ID gefunden: Label überspringen (kein Fehler)
if (!attachmentId) {
  return { json: { _skip_label: true, label_url: null, label_name: null } };
}

return { json: {
  label_page_id: attachmentId,
  label_name: labelName,
  label_url: 'https://blboardsolutions.atlassian.net/wiki/rest/api/content/' + attachmentId + '/label'
} };

const results = ($input.first().json.results || []);
if (results.length === 0) return [{ json: { _kein_archiv: true } }];

const items = [];
for (const page of results) {
  const props = page.properties;
  const title = props.Titel?.title?.[0]?.plain_text || '';
  const idsRaw = props['Confluence PageID']?.rich_text?.[0]?.plain_text || '';
  // Jede kommaseparierte ID als eigenes Item
  const ids = idsRaw.split(',').map(function(s){return s.trim();}).filter(Boolean);
  for (const cId of ids) {
    items.push({ json: {
      notion_page_id: page.id,
      title: title,
      confluence_id: cId
    }});
  }
}
return items.length > 0 ? items : [{ json: { _kein_archiv: true } }];

const loopItem = $('Loop: Archiv-Dokumente').item.json;
const results = ($input.item.json.results || []);

// Exakten Anhang per Dateiname finden
const match = results.find(function(att) {
  return att.title === loopItem.filename;
});

// Fallback: ersten PDF-Anhang nehmen falls kein Namens-Match
const fallback = results.find(function(att) {
  return (att.title || '').toLowerCase().endsWith('.pdf');
});

const attachmentId = (match || fallback || {}).id || '';
console.log('[ARCHIV] Datei:', loopItem.filename, '| Match:', !!match, '| Fallback:', !!fallback, '| ID:', attachmentId || '-');

return { json: {
  notion_page_id: loopItem.notion_page_id,
  filename: loopItem.filename,
  attachment_id: attachmentId,
  has_attachment: !!attachmentId
} };
